17	/// An ordered map based on a lock-free skip list.
18	///
19	/// This is an alternative to [`BTreeMap`] which supports
20	/// concurrent access across multiple threads.
21	///
22	/// A custom comparator may be provided, causing all keys
23	/// to be ordered by the comparison function used instead
24	/// of the standard `Ord` impl. See [`Comparator`].
25	///
26	/// [`BTreeMap`]: std::collections::BTreeMap
27	/// [`Comparator`]: crate::comparator::Comparator
28	pub struct SkipMap<K, V, C = BasicComparator> {
29	    inner: base::SkipList<K, V, C>,
30	}
31	
32	impl<K, V> SkipMap<K, V> {
33	    /// Returns a new, empty map with the default comparator.
34	    ///
35	    /// # Example
36	    ///
37	    /// ```
38	    /// use crossbeam_skiplist::SkipMap;
39	    ///
40	    /// let map: SkipMap<i32, &str> = SkipMap::new();
41	    /// ```
42	    pub fn new() -> Self {
43	        Self {
44	            inner: base::SkipList::new(epoch::default_collector().clone()),
45	        }
46	    }
47	}
48	
49	impl<K, V, C> SkipMap<K, V, C> {
50	    /// Returns a new, empty map with the given comparator.
51	    ///
52	    /// # Example
53	    ///
54	    /// ```
55	    /// use crossbeam_skiplist::{SkipMap, comparator::BasicComparator};
56	    ///
57	    /// let map: SkipMap<i32, &str> = SkipMap::with_comparator(BasicComparator);
58	    /// ```
59	    pub fn with_comparator(comparator: C) -> Self {
60	        Self {
61	            inner: base::SkipList::with_comparator(epoch::default_collector().clone(), comparator),
62	        }
63	    }
64	
65	    /// Returns `true` if the map is empty.
66	    ///
67	    /// # Example
68	    /// ```
69	    /// use crossbeam_skiplist::SkipMap;
70	    ///
71	    /// let map: SkipMap<&str, &str> = SkipMap::new();
72	    /// assert!(map.is_empty());
73	    ///
74	    /// map.insert("key", "value");
75	    /// assert!(!map.is_empty());
76	    /// ```
77	    pub fn is_empty(&self) -> bool {
78	        self.inner.is_empty()
79	    }
80	
81	    /// Returns the number of entries in the map.
82	    ///
83	    /// If the map is being concurrently modified, consider the returned number just an
84	    /// approximation without any guarantees.
85	    ///
86	    /// # Example
87	    /// ```
88	    /// use crossbeam_skiplist::SkipMap;
89	    ///
90	    /// let map = SkipMap::new();
91	    /// map.insert(0, 1);
92	    /// assert_eq!(map.len(), 1);
93	    ///
94	    /// for x in 1..=5 {
95	    ///     map.insert(x, x + 1);
96	    /// }
97	    ///
98	    /// assert_eq!(map.len(), 6);
99	    /// ```
100	    pub fn len(&self) -> usize {
101	        self.inner.len()
102	    }
103	}
104	
105	impl<K, V, C> SkipMap<K, V, C>
106	where
107	    C: Comparator<K>,
108	{
109	    /// Returns the entry with the smallest key.
110	    ///
111	    /// This function returns an [`Entry`] which
112	    /// can be used to access the key's associated value.
113	    ///
114	    /// # Example
115	    /// ```
116	    /// use crossbeam_skiplist::SkipMap;
117	    ///
118	    /// let numbers = SkipMap::new();
119	    /// numbers.insert(5, "five");
120	    /// assert_eq!(*numbers.front().unwrap().value(), "five");
121	    /// numbers.insert(6, "six");
122	    /// assert_eq!(*numbers.front().unwrap().value(), "five");
123	    /// ```
124	    pub fn front(&self) -> Option<Entry<'_, K, V, C>> {
125	        let guard = &epoch::pin();
126	        try_pin_loop(|| self.inner.front(guard)).map(Entry::new)
127	    }
128	
129	    /// Returns the entry with the largest key.
130	    ///
131	    /// This function returns an [`Entry`] which
132	    /// can be used to access the key's associated value.
133	    ///
134	    /// # Example
135	    /// ```
136	    /// use crossbeam_skiplist::SkipMap;
137	    ///
138	    /// let numbers = SkipMap::new();
139	    /// numbers.insert(5, "five");
140	    /// assert_eq!(*numbers.back().unwrap().value(), "five");
141	    /// numbers.insert(6, "six");
142	    /// assert_eq!(*numbers.back().unwrap().value(), "six");
143	    /// ```
144	    pub fn back(&self) -> Option<Entry<'_, K, V, C>> {
145	        let guard = &epoch::pin();
146	        try_pin_loop(|| self.inner.back(guard)).map(Entry::new)
147	    }
148	
149	    /// Finds an entry with the specified key, or inserts a new `key`-`value` pair if none exist.
150	    ///
151	    /// This function returns an [`Entry`] which
152	    /// can be used to access the key's associated value.
153	    ///
154	    /// # Example
155	    /// ```
156	    /// use crossbeam_skiplist::SkipMap;
157	    ///
158	    /// let ages = SkipMap::new();
159	    /// let gates_age = ages.get_or_insert("Bill Gates", 64);
160	    /// assert_eq!(*gates_age.value(), 64);
161	    ///
162	    /// ages.insert("Steve Jobs", 65);
163	    /// let jobs_age = ages.get_or_insert("Steve Jobs", -1);
164	    /// assert_eq!(*jobs_age.value(), 65);
165	    /// ```
166	    pub fn get_or_insert(&self, key: K, value: V) -> Entry<'_, K, V, C> {
167	        let guard = &epoch::pin();
168	        Entry::new(self.inner.get_or_insert(key, value, guard))
169	    }
170	
171	    /// Finds an entry with the specified key, or inserts a new `key`-`value` pair if none exist,
172	    /// where value is calculated with a function.
173	    ///
174	    /// <b>Note:</b> Another thread may write key value first, leading to the result of this closure
175	    /// discarded. If closure is modifying some other state (such as shared counters or shared
176	    /// objects), it may lead to <u>undesired behaviour</u> such as counters being changed without
177	    /// result of closure inserted
178	    ///
179	    /// This function returns an [`Entry`] which
180	    /// can be used to access the key's associated value.
181	    ///
182	    /// # Example
183	    /// ```
184	    /// use crossbeam_skiplist::SkipMap;
185	    ///
186	    /// let ages = SkipMap::new();
187	    /// let gates_age = ages.get_or_insert_with("Bill Gates", || 64);
188	    /// assert_eq!(*gates_age.value(), 64);
189	    ///
190	    /// ages.insert("Steve Jobs", 65);
191	    /// let jobs_age = ages.get_or_insert_with("Steve Jobs", || -1);
192	    /// assert_eq!(*jobs_age.value(), 65);
193	    /// ```
194	    pub fn get_or_insert_with<F>(&self, key: K, value_fn: F) -> Entry<'_, K, V, C>
195	    where
196	        F: FnOnce() -> V,
197	    {
198	        let guard = &epoch::pin();
199	        Entry::new(self.inner.get_or_insert_with(key, value_fn, guard))
200	    }
201	
202	    /// Returns an iterator over all entries in the map,
203	    /// sorted by key.
204	    ///
205	    /// This iterator returns [`Entry`]s which
206	    /// can be used to access keys and their associated values.
207	    ///
208	    /// # Examples
209	    /// ```
210	    /// use crossbeam_skiplist::SkipMap;
211	    ///
212	    /// let numbers = SkipMap::new();
213	    /// numbers.insert(6, "six");
214	    /// numbers.insert(7, "seven");
215	    /// numbers.insert(12, "twelve");
216	    ///
217	    /// // Print then numbers from least to greatest
218	    /// for entry in numbers.iter() {
219	    ///     let number = entry.key();
220	    ///     let number_str = entry.value();
221	    ///     println!("{} is {}", number, number_str);
222	    /// }
223	    /// ```
224	    pub fn iter(&self) -> Iter<'_, K, V, C> {
225	        Iter {
226	            inner: self.inner.ref_iter(),
227	        }
228	    }
229	}
