231	impl<K, V, C> SkipMap<K, V, C>
232	where
233	    C: Comparator<K>,
234	{
235	    /// Returns `true` if the map contains a value for the specified key.
236	    ///
237	    /// # Example
238	    /// ```
239	    /// use crossbeam_skiplist::SkipMap;
240	    ///
241	    /// let ages = SkipMap::new();
242	    /// ages.insert("Bill Gates", 64);
243	    ///
244	    /// assert!(ages.contains_key(&"Bill Gates"));
245	    /// assert!(!ages.contains_key(&"Steve Jobs"));
246	    /// ```
247	    pub fn contains_key<Q>(&self, key: &Q) -> bool
248	    where
249	        C: Comparator<K, Q>,
250	        Q: ?Sized,
251	    {
252	        let guard = &epoch::pin();
253	        self.inner.contains_key(key, guard)
254	    }
255	
256	    /// Returns an entry with the specified `key`.
257	    ///
258	    /// This function returns an [`Entry`] which
259	    /// can be used to access the key's associated value.
260	    ///
261	    /// # Example
262	    /// ```
263	    /// use crossbeam_skiplist::SkipMap;
264	    ///
265	    /// let numbers: SkipMap<&str, i32> = SkipMap::new();
266	    /// assert!(numbers.get("six").is_none());
267	    ///
268	    /// numbers.insert("six", 6);
269	    /// assert_eq!(*numbers.get("six").unwrap().value(), 6);
270	    /// ```
271	    pub fn get<Q>(&self, key: &Q) -> Option<Entry<'_, K, V, C>>
272	    where
273	        C: Comparator<K, Q>,
274	        Q: ?Sized,
275	    {
276	        let guard = &epoch::pin();
277	        try_pin_loop(|| self.inner.get(key, guard)).map(Entry::new)
278	    }
279	
280	    /// Returns an `Entry` pointing to the lowest element whose key is above
281	    /// the given bound. If no such element is found then `None` is
282	    /// returned.
283	    ///
284	    /// This function returns an [`Entry`] which
285	    /// can be used to access the key's associated value.
286	    ///
287	    /// # Example
288	    /// ```
289	    /// use crossbeam_skiplist::SkipMap;
290	    /// use std::ops::Bound::*;
291	    ///
292	    /// let numbers = SkipMap::new();
293	    /// numbers.insert(6, "six");
294	    /// numbers.insert(7, "seven");
295	    /// numbers.insert(12, "twelve");
296	    ///
297	    /// let greater_than_five = numbers.lower_bound(Excluded(&5)).unwrap();
298	    /// assert_eq!(*greater_than_five.value(), "six");
299	    ///
300	    /// let greater_than_six = numbers.lower_bound(Excluded(&6)).unwrap();
301	    /// assert_eq!(*greater_than_six.value(), "seven");
302	    ///
303	    /// let greater_than_thirteen = numbers.lower_bound(Excluded(&13));
304	    /// assert!(greater_than_thirteen.is_none());
305	    /// ```
306	    pub fn lower_bound<'a, Q>(&'a self, bound: Bound<&Q>) -> Option<Entry<'a, K, V, C>>
307	    where
308	        C: Comparator<K, Q>,
309	        Q: ?Sized,
310	    {
311	        let guard = &epoch::pin();
312	        try_pin_loop(|| self.inner.lower_bound(bound, guard)).map(Entry::new)
313	    }
314	
315	    /// Returns an `Entry` pointing to the highest element whose key is below
316	    /// the given bound. If no such element is found then `None` is
317	    /// returned.
318	    ///
319	    /// This function returns an [`Entry`] which
320	    /// can be used to access the key's associated value.
321	    ///
322	    /// # Example
323	    /// ```
324	    /// use crossbeam_skiplist::SkipMap;
325	    /// use std::ops::Bound::*;
326	    ///
327	    /// let numbers = SkipMap::new();
328	    /// numbers.insert(6, "six");
329	    /// numbers.insert(7, "seven");
330	    /// numbers.insert(12, "twelve");
331	    ///
332	    /// let less_than_eight = numbers.upper_bound(Excluded(&8)).unwrap();
333	    /// assert_eq!(*less_than_eight.value(), "seven");
334	    ///
335	    /// let less_than_six = numbers.upper_bound(Excluded(&6));
336	    /// assert!(less_than_six.is_none());
337	    /// ```
338	    pub fn upper_bound<'a, Q>(&'a self, bound: Bound<&Q>) -> Option<Entry<'a, K, V, C>>
339	    where
340	        C: Comparator<K, Q>,
341	        Q: ?Sized,
342	    {
343	        let guard = &epoch::pin();
344	        try_pin_loop(|| self.inner.upper_bound(bound, guard)).map(Entry::new)
345	    }
346	
347	    /// Returns an iterator over a subset of entries in the map.
348	    ///
349	    /// This iterator returns [`Entry`]s which
350	    /// can be used to access keys and their associated values.
351	    ///
352	    /// # Example
353	    /// ```
354	    /// use crossbeam_skiplist::SkipMap;
355	    ///
356	    /// let numbers = SkipMap::new();
357	    /// numbers.insert(6, "six");
358	    /// numbers.insert(7, "seven");
359	    /// numbers.insert(12, "twelve");
360	    ///
361	    /// // Print all numbers in the map between 5 and 8.
362	    /// for entry in numbers.range(5..=8) {
363	    ///     let number = entry.key();
364	    ///     let number_str = entry.value();
365	    ///     println!("{} is {}", number, number_str);
366	    /// }
367	    /// ```
368	    pub fn range<Q, R>(&self, range: R) -> Range<'_, Q, R, K, V, C>
369	    where
370	        R: RangeBounds<Q>,
371	        C: Comparator<K, Q>,
372	        Q: ?Sized,
373	    {
374	        Range {
375	            inner: self.inner.ref_range(range),
376	        }
377	    }
378	}
