380	impl<K, V, C> SkipMap<K, V, C>
381	where
382	    C: Comparator<K>,
383	    K: Send + 'static,
384	    V: Send + 'static,
385	{
386	    /// Inserts a `key`-`value` pair into the map and returns the new entry.
387	    ///
388	    /// If there is an existing entry with this key, it will be removed before inserting the new
389	    /// one.
390	    ///
391	    /// This function returns an [`Entry`] which
392	    /// can be used to access the inserted key's associated value.
393	    ///
394	    /// # Example
395	    /// ```
396	    /// use crossbeam_skiplist::SkipMap;
397	    ///
398	    /// let map = SkipMap::new();
399	    /// map.insert("key", "value");
400	    ///
401	    /// assert_eq!(*map.get("key").unwrap().value(), "value");
402	    /// ```
403	    pub fn insert(&self, key: K, value: V) -> Entry<'_, K, V, C> {
404	        let guard = &epoch::pin();
405	        Entry::new(self.inner.insert(key, value, guard))
406	    }
407	
408	    /// Inserts a `key`-`value` pair into the skip list and returns the new entry.
409	    ///
410	    /// If there is an existing entry with this key and compare(entry.value) returns true,
411	    /// it will be removed before inserting the new one.
412	    /// The closure will not be called if the key is not present.
413	    ///
414	    /// This function returns an [`Entry`] which
415	    /// can be used to access the inserted key's associated value.
416	    ///
417	    /// # Example
418	    /// ```
419	    /// use crossbeam_skiplist::SkipMap;
420	    ///
421	    /// let map = SkipMap::new();
422	    /// map.insert("key", 1);
423	    /// map.compare_insert("key", 0, |x| x < &0);
424	    /// assert_eq!(*map.get("key").unwrap().value(), 1);
425	    /// map.compare_insert("key", 2, |x| x < &2);
426	    /// assert_eq!(*map.get("key").unwrap().value(), 2);
427	    /// map.compare_insert("absent_key", 0, |_| false);
428	    /// assert_eq!(*map.get("absent_key").unwrap().value(), 0);
429	    /// ```
430	    pub fn compare_insert<F>(&self, key: K, value: V, compare_fn: F) -> Entry<'_, K, V, C>
431	    where
432	        F: Fn(&V) -> bool,
433	    {
434	        let guard = &epoch::pin();
435	        Entry::new(self.inner.compare_insert(key, value, compare_fn, guard))
436	    }
437	
438	    /// Removes an entry with the specified `key` from the map and returns it.
439	    ///
440	    /// The value will not actually be dropped until all references to it have gone
441	    /// out of scope.
442	    ///
443	    /// This function returns an [`Entry`] which
444	    /// can be used to access the removed key's associated value.
445	    ///
446	    /// # Example
447	    /// ```
448	    /// use crossbeam_skiplist::SkipMap;
449	    ///
450	    /// let map: SkipMap<&str, &str> = SkipMap::new();
451	    /// assert!(map.remove("invalid key").is_none());
452	    ///
453	    /// map.insert("key", "value");
454	    /// assert_eq!(*map.remove("key").unwrap().value(), "value");
455	    /// ```
456	    pub fn remove<Q>(&self, key: &Q) -> Option<Entry<'_, K, V, C>>
457	    where
458	        C: Comparator<K, Q>,
459	        Q: ?Sized,
460	    {
461	        let guard = &epoch::pin();
462	        self.inner.remove(key, guard).map(Entry::new)
463	    }
464	
465	    /// Removes the entry with the lowest key
466	    /// from the map. Returns the removed entry.
467	    ///
468	    /// The value will not actually be dropped until all references to it have gone
469	    /// out of scope.
470	    ///
471	    /// # Example
472	    /// ```
473	    /// use crossbeam_skiplist::SkipMap;
474	    ///
475	    /// let numbers = SkipMap::new();
476	    /// numbers.insert(6, "six");
477	    /// numbers.insert(7, "seven");
478	    /// numbers.insert(12, "twelve");
479	    ///
480	    /// assert_eq!(*numbers.pop_front().unwrap().value(), "six");
481	    /// assert_eq!(*numbers.pop_front().unwrap().value(), "seven");
482	    /// assert_eq!(*numbers.pop_front().unwrap().value(), "twelve");
483	    ///
484	    /// // All entries have been removed now.
485	    /// assert!(numbers.is_empty());
486	    /// ```
487	    pub fn pop_front(&self) -> Option<Entry<'_, K, V, C>> {
488	        let guard = &epoch::pin();
489	        self.inner.pop_front(guard).map(Entry::new)
490	    }
491	
492	    /// Removes the entry with the greatest key from the map.
493	    /// Returns the removed entry.
494	    ///
495	    /// The value will not actually be dropped until all references to it have gone
496	    /// out of scope.
497	    ///
498	    /// # Example
499	    /// ```
500	    /// use crossbeam_skiplist::SkipMap;
501	    ///
502	    /// let numbers = SkipMap::new();
503	    /// numbers.insert(6, "six");
504	    /// numbers.insert(7, "seven");
505	    /// numbers.insert(12, "twelve");
506	    ///
507	    /// assert_eq!(*numbers.pop_back().unwrap().value(), "twelve");
508	    /// assert_eq!(*numbers.pop_back().unwrap().value(), "seven");
509	    /// assert_eq!(*numbers.pop_back().unwrap().value(), "six");
510	    ///
511	    /// // All entries have been removed now.
512	    /// assert!(numbers.is_empty());
513	    /// ```
514	    pub fn pop_back(&self) -> Option<Entry<'_, K, V, C>> {
515	        let guard = &epoch::pin();
516	        self.inner.pop_back(guard).map(Entry::new)
517	    }
518	
519	    /// Removes all entries from the map.
520	    ///
521	    /// # Example
522	    /// ```
523	    /// use crossbeam_skiplist::SkipMap;
524	    ///
525	    /// let people = SkipMap::new();
526	    /// people.insert("Bill", "Gates");
527	    /// people.insert("Steve", "Jobs");
528	    ///
529	    /// people.clear();
530	    /// assert!(people.is_empty());
531	    /// ```
532	    pub fn clear(&self) {
533	        let guard = &mut epoch::pin();
534	        self.inner.clear(guard);
535	    }
536	}
