580	impl<K, V, C> FromIterator<(K, V)> for SkipMap<K, V, C>
581	where
582	    C: Comparator<K> + Default,
583	{
584	    fn from_iter<I>(iter: I) -> Self
585	    where
586	        I: IntoIterator<Item = (K, V)>,
587	    {
588	        let s = Self::default();
589	        for (k, v) in iter {
590	            s.get_or_insert(k, v);
591	        }
592	        s
