596	/// A reference-counted entry in a map.
597	pub struct Entry<'a, K, V, C = BasicComparator> {
598	    inner: ManuallyDrop<base::RefEntry<'a, K, V, C>>,
599	}
600	
601	impl<'a, K, V, C> Entry<'a, K, V, C> {
602	    fn new(inner: base::RefEntry<'a, K, V, C>) -> Self {
603	        Self {
604	            inner: ManuallyDrop::new(inner),
605	        }
606	    }
607	
608	    /// Returns a reference to the key.
609	    pub fn key(&self) -> &K {
610	        self.inner.key()
611	    }
612	
613	    /// Returns a reference to the value.
614	    pub fn value(&self) -> &V {
615	        self.inner.value()
616	    }
617	
618	    /// Returns `true` if the entry is removed from the map.
619	    pub fn is_removed(&self) -> bool {
620	        self.inner.is_removed()
621	    }
622	}
623	
624	impl<K, V, C> Drop for Entry<'_, K, V, C> {
625	    fn drop(&mut self) {
626	        unsafe {
627	            ManuallyDrop::into_inner(ptr::read(&self.inner)).release_with_pin(epoch::pin);
628	        }
629	    }
630	}
631	
632	impl<K, V, C> Entry<'_, K, V, C>
633	where
634	    C: Comparator<K>,
635	{
636	    /// Moves to the next entry in the map.
637	    pub fn move_next(&mut self) -> bool {
638	        let guard = &epoch::pin();
639	        self.inner.move_next(guard)
640	    }
641	
642	    /// Moves to the previous entry in the map.
